#include <ck/library/tensor_operation_instance/gpu/grouped_convolution_forward_bias_clamp.hpp>

#include "testing_utils.hpp"

using ck_tile::test::InstanceSet;
using ck_tile::test::InstancesMatch;

namespace {

using InLayout  = ck::tensor_layout::convolution::NHWGC;
using WeiLayout = ck::tensor_layout::convolution::GKYXC;
using OutLayout = ck::tensor_layout::convolution::NHWGK;

using ck::tensor_operation::device::DeviceGroupedConvFwdMultipleABD;
using ck::tensor_operation::element_wise::AddClamp;
using ck::tensor_operation::element_wise::PassThrough;

template <ck::index_t NumDimSpatial, typename T, typename ComputeType>
struct DeviceOpHelper;

template <typename T, typename ComputeType>
struct DeviceOpHelper<2, T, ComputeType>
{
    using InLayout  = ck::tensor_layout::convolution::NHWGC;
    using WeiLayout = ck::tensor_layout::convolution::GKYXC;
    using OutLayout = ck::tensor_layout::convolution::NHWGK;

    using Type = DeviceGroupedConvFwdMultipleABD<2,
                                                 InLayout,
                                                 WeiLayout,
                                                 ck::Tuple<OutLayout>, // DsLayout
                                                 OutLayout,
                                                 T,            // InDataType
                                                 T,            // WeiDataType
                                                 ck::Tuple<T>, // DsDataType
                                                 T,            // OutDataType
                                                 PassThrough,
                                                 PassThrough,
                                                 AddClamp,
                                                 ComputeType>;
};

template <typename T, typename ComputeType>
struct DeviceOpHelper<3, T, ComputeType>
{
    using InLayout  = ck::tensor_layout::convolution::NDHWGC;
    using WeiLayout = ck::tensor_layout::convolution::GKZYXC;
    using OutLayout = ck::tensor_layout::convolution::NDHWGK;

    using Type = DeviceGroupedConvFwdMultipleABD<3,
                                                 InLayout,
                                                 WeiLayout,
                                                 ck::Tuple<OutLayout>, // DsLayout
                                                 OutLayout,
                                                 T,            // InDataType
                                                 T,            // WeiDataType
                                                 ck::Tuple<T>, // DsDataType
                                                 T,            // OutDataType
                                                 PassThrough,
                                                 PassThrough,
                                                 AddClamp,
                                                 ComputeType>;
};

template <ck::index_t NumDimSpatial, typename T, typename ComputeType = T>
using DeviceOp = DeviceOpHelper<NumDimSpatial, T, ComputeType>::Type;

} // namespace

template <typename Case>
struct CkFactoryTestConvFwd : public testing::Test
{
    static auto get_actual_instances()
    {
        return InstanceSet::from_factory<typename Case::DeviceOp>();
    }

    static auto get_expected_instances() { return InstanceSet(Case::expected); }
};

